import { useEffect, useState } from 'react';
import api from '../api/client';

export default function TicketList({
  refreshKey = 0,
}) {
  // ------------------------
  // STATES
  // ------------------------
  const [tickets, setTickets] =
    useState([]);

  // FILTERS
  const [
    ticketIdSearch,
    setTicketIdSearch,
  ] = useState('');

  const [
    departmentFilter,
    setDepartmentFilter,
  ] = useState('');

  const [
    divisionSearch,
    setDivisionSearch,
  ] = useState('');

  const [
    moduleFilter,
    setModuleFilter,
  ] = useState('');

  const [
    submoduleFilter,
    setSubmoduleFilter,
  ] = useState('');

  const [status, setStatus] =
    useState('');

  const [
  createdFromDate,
  setCreatedFromDate,
] = useState('');

const [
  createdToDate,
  setCreatedToDate,
] = useState('');

  // DROPDOWNS
  const [
    departments,
    setDepartments,
  ] = useState([]);

  const [modules, setModules] =
    useState([]);

  const [
    submodules,
    setSubmodules,
  ] = useState([]);

  // PAGINATION
  const [page, setPage] =
    useState(1);

  const [count, setCount] =
    useState(0);

  const [nextPage, setNextPage] =
    useState(null);

  const [
    previousPage,
    setPreviousPage,
  ] = useState(null);

  // ------------------------
  // LOAD DROPDOWNS
  // ------------------------
  const loadDropdowns =
    async () => {
      try {
        const [
          deptRes,
          moduleRes,
          submoduleRes,
        ] = await Promise.all([
          api.get(
            '/masters/departments/'
          ),
          api.get(
            '/masters/modules/'
          ),
          api.get(
            '/masters/submodules/'
          ),
        ]);

        setDepartments(
          deptRes.data.results ||
            deptRes.data ||
            []
        );

        setModules(
          moduleRes.data.results ||
            moduleRes.data ||
            []
        );

        setSubmodules(
          submoduleRes.data.results ||
            submoduleRes.data ||
            []
        );
      } catch (err) {
        console.error(
          'Dropdown load failed:',
          err
        );
      }
    };

  // ------------------------
  // FILTER MODULES
  // ------------------------
  const filteredModules =
    !departmentFilter
      ? modules
      : modules.filter(
          (module) =>
            Number(
              module.department ||
                module.department_id
            ) ===
            Number(
              departmentFilter
            )
        );

  // ------------------------
  // FILTER SUBMODULES
  // ------------------------
  const filteredSubmodules =
    !moduleFilter
      ? submodules
      : submodules.filter(
          (submodule) =>
            Number(
              submodule.module
            ) ===
            Number(
              moduleFilter
            )
        );

  // ------------------------
  // LOAD TICKETS
  // ------------------------
  const loadTickets =
    async (pageNo = page) => {
      try {
        const params = {
          page: pageNo,
        };

        if (ticketIdSearch) {
          params.ticket_id =
            ticketIdSearch;
        }

        if (
          departmentFilter
        ) {
          params.department =
            departmentFilter;
        }

        if (
          divisionSearch
        ) {
          params.division_name =
            divisionSearch;
        }

        if (moduleFilter) {
          params.module =
            moduleFilter;
        }

        if (
          submoduleFilter
        ) {
          params.submodule =
            submoduleFilter;
        }

        if (status) {
          params.status =
            status;
        }

        // DATE FILTERS
        if (createdDate) {
          params.created_at =
            createdDate;
        }

        if (closedDate) {
          params.closed_at =
            closedDate;
        }

        const res =
          await api.get(
            '/tickets/',
            { params }
          );

        const data =
          res.data;

        setTickets(
          data.results || []
        );

        setCount(
          data.count || 0
        );

        setNextPage(
          data.next
        );

        setPreviousPage(
          data.previous
        );
      } catch (err) {
        console.error(
          'Ticket load failed:',
          err
        );
      }
    };

  // ------------------------
  // INITIAL LOAD
  // ------------------------
  useEffect(() => {
    loadDropdowns();
  }, []);

  // RESET PAGE
  useEffect(() => {
    setPage(1);
  }, [
    ticketIdSearch,
    departmentFilter,
    divisionSearch,
    moduleFilter,
    submoduleFilter,
    status,
    createdFromDate,
    createdToDate,
  ]);

  // LOAD TICKETS
  useEffect(() => {
    loadTickets(page);
  }, [
    refreshKey,
    page,
    ticketIdSearch,
    departmentFilter,
    divisionSearch,
    moduleFilter,
    submoduleFilter,
    status,
    createdFromDate,
    createdToDate,
  ]);

  // ------------------------
  // RESET FILTERS
  // ------------------------
  const handleResetFilters =
    () => {
      setTicketIdSearch('');
      setDepartmentFilter(
        ''
      );
      setDivisionSearch('');
      setModuleFilter('');
      setSubmoduleFilter(
        ''
      );
      setStatus('');
      setCreatedDate('');
      setClosedDate('');
      setPage(1);
    };

  // ------------------------
  // EXPORT EXCEL
  // ------------------------
  const handleExport =
    async () => {
      try {
        const params = {};

        if (ticketIdSearch)
          params.ticket_id =
            ticketIdSearch;

        if (
          departmentFilter
        )
          params.department =
            departmentFilter;

        if (
          divisionSearch
        )
          params.division_name =
            divisionSearch;

        if (moduleFilter)
          params.module =
            moduleFilter;

        if (
          submoduleFilter
        )
          params.submodule =
            submoduleFilter;

        if (status)
          params.status =
            status;

        if (createdFromDate) {
          params.created_from =
            createdFromDate;
        }

        if (createdToDate) {
          params.created_to =
            createdToDate;
}

        const res =
          await api.get(
            '/tickets/export_excel/',
            {
              params,
              responseType:
                'blob',
            }
          );

        const url =
          window.URL.createObjectURL(
            new Blob([
              res.data,
            ])
          );

        const link =
          document.createElement(
            'a'
          );

        link.href = url;

        link.setAttribute(
          'download',
          'tickets.xlsx'
        );

        document.body.appendChild(
          link
        );

        link.click();
        link.remove();
      } catch (err) {
        console.error(
          'Export failed:',
          err
        );
      }
    };

  const totalPages =
    Math.ceil(
      count / 8
    );

  return (
    <div>
      {/* FILTERS */}
      <div className="row mb-3 g-2">

        <div className="col-md-2">
          <input
            type="text"
            className="form-control"
            placeholder="Ticket ID"
            value={
              ticketIdSearch
            }
            onChange={(e) =>
              setTicketIdSearch(
                e.target.value
              )
            }
          />
        </div>

        <div className="col-md-2">
          <select
            className="form-select"
            value={
              departmentFilter
            }
            onChange={(e) => {
              setDepartmentFilter(
                e.target.value
              );
              setModuleFilter(
                ''
              );
              setSubmoduleFilter(
                ''
              );
            }}
          >
            <option value="">
              All Departments
            </option>

            {departments.map(
              (dept) => (
                <option
                  key={
                    dept.id
                  }
                  value={
                    dept.id
                  }
                >
                  {
                    dept.department_name
                  }
                </option>
              )
            )}
          </select>
        </div>

        <div className="col-md-2">
          <select
            className="form-select"
            value={
              moduleFilter
            }
            onChange={(e) => {
              setModuleFilter(
                e.target.value
              );
              setSubmoduleFilter(
                ''
              );
            }}
          >
            <option value="">
              All Modules
            </option>

            {filteredModules.map(
              (
                module
              ) => (
                <option
                  key={
                    module.id
                  }
                  value={
                    module.id
                  }
                >
                  {
                    module.module_name
                  }
                </option>
              )
            )}
          </select>
        </div>

        <div className="col-md-2">
          <select
            className="form-select"
            value={
              submoduleFilter
            }
            onChange={(e) =>
              setSubmoduleFilter(
                e.target.value
              )
            }
            disabled={
              !moduleFilter
            }
          >
            <option value="">
              All Submodules
            </option>

            {filteredSubmodules.map(
              (
                submodule
              ) => (
                <option
                  key={
                    submodule.id
                  }
                  value={
                    submodule.id
                  }
                >
                  {
                    submodule.submodule_name
                  }
                </option>
              )
            )}
          </select>
        </div>

        <div className="col-md-2">
          <input
            type="date"
            className="form-control"
            value={
              createdDate
            }
            onChange={(e) =>
              setCreatedDate(
                e.target.value
              )
            }
          />
        </div>

        <div className="col-md-2">
          <input
            type="date"
            className="form-control"
            value={
              closedDate
            }
            onChange={(e) =>
              setClosedDate(
                e.target.value
              )
            }
          />
        </div>
      </div>

      <div className="mb-3 d-flex gap-2">
        <button
          className="btn btn-secondary"
          onClick={
            handleResetFilters
          }
        >
          Reset
        </button>

        <button
          className="btn btn-success"
          onClick={
            handleExport
          }
        >
          Export Excel
        </button>
      </div>

      {/* TABLE */}
      <div className="table-responsive">
        <table className="table table-bordered table-striped">
          <thead>
            <tr>
              <th>Ticket ID</th>
              <th>Department</th>
              <th>Module</th>
              <th>Submodule</th>
              <th>Subject</th>
              <th>Status</th>
              <th>Created Date</th>
              <th>Closed Date</th>
            </tr>
          </thead>

          <tbody>
            {tickets.length >
            0 ? (
              tickets.map(
                (ticket) => (
                  <tr
                    key={
                      ticket.id
                    }
                  >
                    <td>
                      {
                        ticket.ticket_id
                      }
                    </td>
                    <td>
                      {
                        ticket.department_name
                      }
                    </td>
                    <td>
                      {
                        ticket.module_name
                      }
                    </td>
                    <td>
                      {
                        ticket.submodule_name
                      }
                    </td>
                    <td>
                      {
                        ticket.subject
                      }
                    </td>
                    <td>
                      {
                        ticket.status
                      }
                    </td>
                    <td>
                      {ticket.created_at
                        ? new Date(
                            ticket.created_at
                          ).toLocaleDateString()
                        : '-'}
                    </td>
                    <td>
                      {ticket.closed_at
                        ? new Date(
                            ticket.closed_at
                          ).toLocaleDateString()
                        : '-'}
                    </td>
                  </tr>
                )
              )
            ) : (
              <tr>
                <td
                  colSpan="8"
                  className="text-center"
                >
                  No tickets found
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* PAGINATION */}
      <div className="d-flex justify-content-between mt-3">
        <button
          className="btn btn-outline-secondary"
          disabled={
            !previousPage
          }
          onClick={() =>
            setPage(
              (prev) =>
                prev - 1
            )
          }
        >
          Previous
        </button>

        <span>
          Page {page} of{' '}
          {totalPages || 1}
        </span>

        <button
          className="btn btn-outline-secondary"
          disabled={
            !nextPage
          }
          onClick={() =>
            setPage(
              (prev) =>
                prev + 1
            )
          }
        >
          Next
        </button>
      </div>
    </div>
  );
}
